// Handle Nominatim response — returns array directly
// n8n wraps it in json so we need to handle both [{}] and {body: [{}]} shapes
const raw = $input.first().json;
const inputs = $('Parse & Validate Inputs').first().json;

// Nominatim returns a JSON array — n8n may parse it as the object itself
// or wrap it. Handle all cases:
let results = [];
if (Array.isArray(raw)) {
  results = raw;
} else if (Array.isArray(raw?.body)) {
  results = raw.body;
} else if (raw?.lat && raw?.lon) {
  // Single object (shouldn't happen but handle anyway)
  results = [raw];
}

const first = results[0] || null;
let lat = first ? parseFloat(first.lat) : null;
let lng = first ? parseFloat(first.lon) : null;

// ── CITY FALLBACK COORDINATES ──
// Used when Nominatim returns no result (e.g. very short street name)
const cityFallbacks = {
  'melbourne': { lat: -37.8136, lng: 144.9631 },
  'sydney':    { lat: -33.8688, lng: 151.2093 },
  'brisbane':  { lat: -27.4698, lng: 153.0251 },
  'perth':     { lat: -31.9505, lng: 115.8605 },
  'adelaide':  { lat: -34.9285, lng: 138.6007 },
  'canberra':  { lat: -35.2809, lng: 149.1300 },
  'hobart':    { lat: -42.8821, lng: 147.3272 },
  'darwin':    { lat: -12.4634, lng: 130.8456 },
  'gold coast':{ lat: -28.0167, lng: 153.4000 },
  'newcastle': { lat: -32.9283, lng: 151.7817 },
  'wollongong':{ lat: -34.4278, lng: 150.8931 },
  'geelong':   { lat: -38.1499, lng: 144.3617 }
};

let geocodeSource = 'Nominatim (exact)';
if (!lat || !lng || isNaN(lat) || isNaN(lng)) {
  const cityLower = (inputs.city || '').toLowerCase();
  for (const [city, coords] of Object.entries(cityFallbacks)) {
    if (cityLower.includes(city)) {
      lat = coords.lat;
      lng = coords.lng;
      geocodeSource = `City fallback — Nominatim returned no result for "${inputs.nominatim_query}"`;
      break;
    }
  }
}

// If still no coordinates, use Melbourne as last resort
if (!lat || !lng) {
  lat = -37.8136;
  lng = 144.9631;
  geocodeSource = 'Default fallback (Melbourne centre) — no geocode result';
}

const locationString = `${lat},${lng}`;

return [{ json: {
  ...inputs,
  lat,
  lng,
  location_string:  locationString,
  geocode_source:   geocodeSource,
  geocode_raw:      first ? { display_name: first.display_name, osm_type: first.osm_type } : null,
  nominatim_found:  !!first
}}];

// ── Cache check (Supabase) ──
// TODO: Before calling expensive APIs, check:
// SELECT * FROM agent_cache WHERE cache_key = MD5(city+area+business_type+agent_id)
//   AND updated_at > NOW() - INTERVAL '7 days'
// If cache hit → return cached data immediately
// Implementation: add a Supabase HTTP call before API calls with cache_key lookup

const inputs = $input.all();
const geo = $('Extract Coordinates').first().json;

const localResults   = inputs[0]?.json?.results || [];
const broaderResults = inputs[1]?.json?.results || [];

// Deduplicate by place_id
const seen = new Set();
const unique = [...localResults, ...broaderResults].filter(p => {
  if (!p.place_id || seen.has(p.place_id)) return false;
  seen.add(p.place_id);
  return true;
});

const localIds = new Set(localResults.map(p => p.place_id));

const competitors = unique.slice(0, 20).map(p => ({
  name:         p.name,
  address:      p.formatted_address || p.vicinity || '',
  rating:       p.rating ?? 'N/A',
  review_count: p.user_ratings_total ?? 0,
  price_level:  p.price_level !== undefined ? '$'.repeat(p.price_level) : 'Unknown',
  open_now:     p.opening_hours?.open_now ?? 'Unknown',
  types:        (p.types || []).slice(0, 4).join(', '),
  within_500m:  localIds.has(p.place_id),
  maps_url:     `https://www.google.com/maps/place/?q=place_id:${p.place_id}`
}));

const within500  = competitors.filter(c => c.within_500m);
const within1500 = competitors.filter(c => !c.within_500m);

const competitorText = competitors.length > 0
  ? competitors.map((c, i) =>
      `${i+1}. ${c.name} [${c.within_500m ? '500m' : '1500m'}]\n   ${c.address}\n   Rating: ${c.rating} (${c.review_count} reviews) | Price: ${c.price_level}`
    ).join('\n\n')
  : `No competitors found via nearbysearch at ${geo.location_string} — geocode source: ${geo.geocode_source}`;

return [{ json: {
  competitors_raw:          competitors,
  competitor_count:         competitors.length,
  competitors_500m:         within500.length,
  competitors_1500m:        within1500.length,
  competitors_text:         competitorText,
  geocode_source:           geo.geocode_source,
  geocode_display:          geo.geocode_raw?.display_name || geo.nominatim_query || '',
  nominatim_found:          geo.nominatim_found,
  lat:                      geo.lat,
  lng:                      geo.lng,
  location_string:          geo.location_string,
  business_type:            geo.business_type,
  industry_category:        geo.industry_category,
  city:                     geo.city,
  area:                     geo.area,
  locality:                 geo.locality,
  pricing_positioning:      geo.pricing_positioning,
  target_customer_segments: geo.target_customer_segments,
  landmark_hint:            geo.landmark_hint,
  maps_type_used:           geo.maps_type
}}];

const rawText = $input.first().json.output || '';
let analysis;
try {
  const cleaned = rawText.replace(/```json\n?/g,'').replace(/```\n?/g,'').trim();
  analysis = JSON.parse(cleaned);
} catch(e) {
  analysis = { parse_error: true, raw_response: rawText };
}

const d = $('Process & Deduplicate Results').first().json;

return [{ json: {
  agent_id:   'A1',
  agent_name: 'Competitor Intelligence (Nearbysearch 500m)',
  status:     analysis.parse_error ? 'error' : 'success',
  timestamp:  new Date().toISOString(),
  inputs_used: {
    business_type:            d.business_type,
    industry_category:        d.industry_category,
    location:                 `${d.locality}, ${d.area}, ${d.city}`,
    pricing_positioning:      d.pricing_positioning,
    target_customer_segments: d.target_customer_segments,
    geocode_source:           d.geocode_source,
    nominatim_found:          d.nominatim_found,
    coordinates:              `${d.lat}, ${d.lng}`
  },
  outputs: {
    competitor_density_score:    analysis.competitor_density_score    ?? null,
    saturation_level:            analysis.saturation_level            || null,
    total_competitors_found:     analysis.total_competitors_found     ?? d.competitor_count,
    competitors_within_500m:     analysis.competitors_within_500m     ?? d.competitors_500m,
    competitors_within_1500m:    analysis.competitors_within_1500m    ?? d.competitors_1500m,
    geocode_accuracy:            analysis.geocode_accuracy            || d.geocode_source,
    competitor_profiles:         analysis.competitor_profiles         || [],
    pricing_bands:               analysis.pricing_bands               || {},
    opportunity_gaps:            analysis.opportunity_gaps            || [],
    threat_summary:              analysis.threat_summary              || null,
    differentiation_suggestions: analysis.differentiation_suggestions || [],
    locality_context:            analysis.locality_context            || null,
    agent_notes:                 analysis.agent_notes                 || null
  },
  raw_maps_data: d.competitors_raw
}}];


// ── Output validation ──
const required_keys = Object.keys(analysis).filter(k => !k.startsWith('_') && !k.startsWith('raw'));
if (required_keys.length < 3 || analysis.parse_error) {
  analysis._validation_failed = true;
  analysis._validation_reason = analysis.parse_error ? 'JSON parse error' : 'Insufficient output fields (' + required_keys.length + ')';
}
analysis._validated_at = new Date().toISOString();
analysis._agent_version = 'v2';
